import{_ as a,o as e,c as d,a2 as o}from"./chunks/framework.BnBoz4Zl.js";const i="/anjian-workbuddy-bluebook-site/assets/001_26MfTlZV_KWt4b43Mbo.BL2m0vhS.jpg",l="/anjian-workbuddy-bluebook-site/assets/002_workbuddy-local-cloud-mode_CsMMbNpDWo.DA75xabT.jpg",s="/anjian-workbuddy-bluebook-site/assets/003_workbuddy-remote-ppt-search_TKo1bTVF0o.BfFv4XFe.jpg",r="/anjian-workbuddy-bluebook-site/assets/004_p8IJTS7o_AFVJb6OkJo.CfzHwxGg.jpg",n="/anjian-workbuddy-bluebook-site/assets/005_workbuddy-remote-task-execute_Aw3vbvuLho.DiXKKEvJ.jpg",p="/anjian-workbuddy-bluebook-site/assets/006_image_GvG6bCfUyo.Beuy0f-O.png",y=JSON.parse('{"title":"第 13 章 远程控制你的电脑，不用发愁不在电脑前","description":"::: warning 安居建业内部使用提示 远程任务仅限已授权设备、账号和目录，不得把项目敏感资料、个人信息或密钥回传到未经批准的终端和聊天渠道。批量改名、覆盖、删除、压缩外发及任何业务系统操作必须暂停并人工确认；任务结束后应核对产物、日志和回退文件。 :::","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md","lastUpdated":1783915201000}'),h={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 13 章 远程控制你的电脑，不用发愁不在电脑前/index.md"};function c(b,t,u,k,g,_){return e(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="第-13-章-远程控制你的电脑-不用发愁不在电脑前" tabindex="-1">第 13 章 远程控制你的电脑，不用发愁不在电脑前 <a class="header-anchor" href="#第-13-章-远程控制你的电脑-不用发愁不在电脑前" aria-label="Permalink to &quot;第 13 章 远程控制你的电脑，不用发愁不在电脑前&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">安居建业内部使用提示</p><p>远程任务仅限已授权设备、账号和目录，不得把项目敏感资料、个人信息或密钥回传到未经批准的终端和聊天渠道。批量改名、覆盖、删除、压缩外发及任何业务系统操作必须暂停并人工确认；任务结束后应核对产物、日志和回退文件。</p></div><p>你人不在电脑前，WorkBuddy 小程序可以成为远程任务入口，把指令发回正在运行的电脑端，让电脑继续查文件、读资料、整理发票、处理微信文件，甚至持续汇报一个长任务的进展。</p><h2 id="小程序远程控制电脑" tabindex="-1">小程序远程控制电脑 <a class="header-anchor" href="#小程序远程控制电脑" aria-label="Permalink to &quot;小程序远程控制电脑&quot;">​</a></h2><p><img src="'+i+'" alt="" loading="lazy"></p><p>传统远程办公通常有两种方式：一种是把电脑屏幕投到手机上，自己点鼠标；另一种是把文件先传到云端，再在手机上处理。</p><p>WorkBuddy 的远程方式介于二者之间：用户不直接操控鼠标，而是把任务说清楚；电脑端 WorkBuddy 根据授权范围读取本地文件、调用 Skill 或本地工具，把中间结果和最终产物回传到手机端。</p><table tabindex="0"><thead><tr><th>能力层</th><th>解决什么问题</th><th>使用时要确认什么</th></tr></thead><tbody><tr><td><strong>手机端入口</strong></td><td>在路上、会议间隙、客户现场也能发起任务</td><td>账号已登录，消息能送达，语音转文字没有关键错误</td></tr><tr><td><strong>电脑端执行</strong></td><td>读取本机目录、调用本地软件、处理私有资料</td><td>电脑在线，WorkBuddy 正在运行，目录权限已授权</td></tr><tr><td><strong>任务回传</strong></td><td>把候选文件、摘要、表格、截图、压缩包返回给手机</td><td>输出路径明确，不覆盖原文件，敏感信息先脱敏</td></tr><tr><td><strong>人工确认</strong></td><td>避免远程状态下误删、误发、误改重要资料</td><td>高风险动作必须暂停确认，不把“执行完”当成“验收完”</td></tr></tbody></table><h2 id="先分清-云端模式还是本机模式" tabindex="-1">先分清：云端模式还是本机模式 <a class="header-anchor" href="#先分清-云端模式还是本机模式" aria-label="Permalink to &quot;先分清：云端模式还是本机模式&quot;">​</a></h2><p>移动端适合在通勤、出差、跨设备办公时继续推进任务。但在使用前，必须先判断任务究竟应该跑在云端，还是跑在本机。</p><p>这个判断会直接影响它能否读取电脑文件、是否需要电脑在线，以及数据是否适合进入云端环境。</p><p><img src="'+l+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>判断问题</th><th>云端模式</th><th>本机模式</th></tr></thead><tbody><tr><td>是否需要电脑在线</td><td>通常不需要</td><td>需要电脑在线，并且 WorkBuddy 处于可响应状态</td></tr><tr><td>能否读取电脑目录</td><td>不能直接读取</td><td>可以读取已授权范围内的本地目录</td></tr><tr><td>适合任务</td><td>公开资料调研、写提纲、生成轻量文本</td><td>查找本机文件、读取私有资料、调用本地 Skill 或软件</td></tr><tr><td>主要风险</td><td>资料是否适合进入云端</td><td>目录权限、误操作、电脑离线、结果未验收</td></tr></tbody></table><h2 id="人在外面-临时要电脑里的文件" tabindex="-1">人在外面，临时要电脑里的文件 <a class="header-anchor" href="#人在外面-临时要电脑里的文件" aria-label="Permalink to &quot;人在外面，临时要电脑里的文件&quot;">​</a></h2><p>这是最容易让用户第一次感受到远程控制价值的场景。合作方突然问培训课件、项目汇报、合同版本、报价单、活动海报源文件在哪里，而资料都在办公室电脑里。过去只能回复“我回去找一下”，现在可以在小程序里语音发起任务，让电脑端 WorkBuddy 在指定目录中查找候选文件，读取内容并整理摘要。</p><h3 id="场景痛点" tabindex="-1">场景痛点 <a class="header-anchor" href="#场景痛点" aria-label="Permalink to &quot;场景痛点&quot;">​</a></h3><ul><li>文件名不一定记得完整，只记得“培训”“项目汇报”“某客户”等关键词。</li><li>电脑里可能有多个版本，远程状态下不能凭感觉直接发。</li><li>临时需求往往只需要先给对方一个摘要或确认口径，不一定马上发送原文件。</li></ul><h3 id="推荐流程" tabindex="-1">推荐流程 <a class="header-anchor" href="#推荐流程" aria-label="Permalink to &quot;推荐流程&quot;">​</a></h3><ol><li>先限定目录，比如桌面、Downloads、项目资料、training 文件夹。</li><li>让 WorkBuddy 只读扫描，列出候选文件、修改时间、文件大小和可能匹配原因。</li><li>确认目标文件后，再读取内容并生成手机端可转发的摘要。</li><li>需要发送文件时，先整理到一个单独输出目录，不直接移动原文件。</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你帮我看一下，我电脑上在我这个local long GPT里边有一个关于xx公司的一些PPT，然后你整理一下内容发给我。</span></span></code></pre></div><p><img src="'+s+'" alt="" loading="lazy"></p><h2 id="微信文件直接处理-不必先搬来搬去" tabindex="-1">微信文件直接处理，不必先搬来搬去 <a class="header-anchor" href="#微信文件直接处理-不必先搬来搬去" aria-label="Permalink to &quot;微信文件直接处理，不必先搬来搬去&quot;">​</a></h2><p>很多任务不是从电脑文件夹开始，而是从微信聊天里突然冒出来：客户发来一个合同 PDF，朋友发来一张票据照片，同事丢来一个 Excel，供应商转来一个压缩包。传统流程是先下载到手机，再传电脑，再找目录，再打开软件。小程序更适合把“微信上下文里的文件”直接变成 WorkBuddy 的输入。</p><p><img src="'+r+'" alt="" loading="lazy"></p><h2 id="远程监控长任务-让手机成为任务看板" tabindex="-1">远程监控长任务，让手机成为任务看板 <a class="header-anchor" href="#远程监控长任务-让手机成为任务看板" aria-label="Permalink to &quot;远程监控长任务，让手机成为任务看板&quot;">​</a></h2><p>远程控制还有一个更进阶的用法：不是让 WorkBuddy 做一个几秒钟的小任务，而是让它持续推进一个需要等待、分阶段处理或容易失败的任务。比如批量转换文件、整理大目录、生成网站、处理会议录音、运行代码测试、下载资料、爬取公开网页、自动化检查系统状态。</p><h3 id="远程监控适合什么" tabindex="-1">远程监控适合什么 <a class="header-anchor" href="#远程监控适合什么" aria-label="Permalink to &quot;远程监控适合什么&quot;">​</a></h3><ul><li>任务耗时超过 3 分钟，需要阶段汇报。</li><li>任务中间可能遇到失败项，需要记录并继续处理其他文件。</li><li>任务结果需要先看预览，再决定是否批量执行下一步。</li><li>任务过程中可能触发登录、付款、发送消息、覆盖文件等高风险动作。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请启动这个批量处理任务，并把手机端当作进度看板。</span></span></code></pre></div><p><img src="'+n+'" alt="" loading="lazy"></p><div class="language-Plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你控制摄像头拍张照片，描述一下电脑前面的画面</span></span></code></pre></div><p><img src="'+p+'" alt="" loading="lazy"></p>',32)])])}const x=a(h,[["render",c]]);export{y as __pageData,x as default};
